            {renderStats()}
          </div>
        </div>
      )}
    </div>
  );
}
/* ── EdaPanel (Dashboard Style) ─────────────────────────────── */
function EdaPanel({ profile, edaInsights, data, question }) {
  const eda  = edaInsights || {};
  const cols = normalizeCols(profile);

  const COL_COLORS = [
    '#6366f1','#22c55e','#f59e0b','#14b8a6',
    '#a855f7','#ef4444','#f97316','#06b6d4'
  ];

  const qualityColor = (score) => {
    if (score >= 80) return { color:'#16a34a', bg:'#f0fdf4', border:'#86efac' };
    if (score >= 60) return { color:'#d97706', bg:'#fffbeb', border:'#fcd34d' };
    return { color:'#dc2626', bg:'#fef2f2', border:'#fca5a5' };
  };

  const MiniBar = ({ value, max, color }) => (
    <div style={{width:'100%', height:4, background:'#f3f4f6', borderRadius:2}}>
      <div style={{
        width:`${max > 0 ? Math.min((value/max)*100, 100) : 0}%`,
        height:'100%', background:color, borderRadius:2,
        transition:'width 0.8s ease'
      }}/>
    </div>
  );

  const MiniDistribution = ({ col, color }) => {
    if (!data?.length) return null;
    const values = data.map(r => r[col.name]).filter(v => v != null);
    const isNum  = col.type === 'numeric';

    if (isNum) {
      const nums = values.map(Number).filter(v => !isNaN(v));
      if (!nums.length) return null;
      const min   = Math.min(...nums);
      const max   = Math.max(...nums);
      const range = max - min || 1;
      const bins  = 8;
      const counts = Array(bins).fill(0);
      nums.forEach(v => {
        const i = Math.min(Math.floor(((v-min)/range)*bins), bins-1);
        counts[i]++;
      });
      const maxC = Math.max(...counts);
      return (
        <div style={{display:'flex', alignItems:'flex-end', gap:2, height:28, marginTop:8}}>
          {counts.map((c, i) => (
            <div key={i} style={{
              flex:1, background:color,
              opacity: 0.2 + (c/maxC)*0.8,
              height:`${maxC > 0 ? (c/maxC)*100 : 0}%`,
              borderRadius:'2px 2px 0 0', minHeight: c > 0 ? 2 : 0,
              transition:'height 0.6s ease'
            }}/>
          ))}
        </div>
      );
    }

    const counts = {};
    values.forEach(v => { counts[String(v)] = (counts[String(v)]||0)+1; });
    const top  = Object.entries(counts).sort((a,b)=>b[1]-a[1]).slice(0,4);
    const maxC = top[0]?.[1] || 1;
    return (
      <div style={{display:'flex', flexDirection:'column', gap:3, marginTop:8}}>
        {top.map(([val, cnt]) => (
          <div key={val} style={{display:'flex', alignItems:'center', gap:6}}>
            <span style={{
              fontSize:9, color:'#6b7591', minWidth:55,
              overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap'
            }}>{val}</span>
            <div style={{flex:1, height:4, background:'#f3f4f6', borderRadius:2}}>
              <div style={{
                width:`${(cnt/maxC)*100}%`, height:'100%',
                background:color, borderRadius:2
              }}/>
            </div>
            <span style={{fontSize:9, color:'#9ca3af', minWidth:14}}>{cnt}</span>
          </div>
        ))}
      </div>
    );
  };

  const rowCount   = data?.length || 0;
  const colCount   = cols.length;
  const nullCols   = cols.filter(c => (c.null_pct||0) > 0).length;
  const numericCols = cols.filter(c => c.type === 'numeric').length;
  const qScore     = eda?.data_quality?.score ?? null;
  const qColors    = qScore !== null ? qualityColor(qScore) : null;

  if (cols.length === 0 && !eda.headline) {
    return (
      <div style={{padding:40, textAlign:'center', color:'#9ca3af', fontSize:13}}>
        No EDA profile available for this result.
      </div>
    );
  }

  return (
    <div style={{padding:'4px 0', display:'flex', flexDirection:'column', gap:14}}>

      {/* ── Top summary stats ── */}
      <div style={{display:'grid', gridTemplateColumns:'repeat(4,1fr)', gap:10}}>
        {[
          {label:'Total Rows',      value:rowCount,     icon:'⊞', color:'#6366f1', bg:'#eef2ff'},
          {label:'Columns',         value:colCount,     icon:'≡',  color:'#0891b2', bg:'#ecfeff'},
          {label:'Numeric Columns', value:numericCols,  icon:'#',  color:'#16a34a', bg:'#f0fdf4'},
          {label:'Cols with Nulls', value:nullCols,
            icon:'∅', color: nullCols>0 ? '#d97706' : '#16a34a',
            bg: nullCols>0 ? '#fffbeb' : '#f0fdf4'},
        ].map(s => (
          <div key={s.label} style={{
            background:s.bg, borderRadius:10,
            padding:'12px 14px', border:`1.5px solid ${s.color}25`
          }}>
            <div style={{fontSize:16, marginBottom:4}}>{s.icon}</div>
            <div style={{fontSize:24, fontWeight:800, color:s.color, lineHeight:1}}>
              {s.value}
            </div>
            <div style={{fontSize:10, color:'#6b7591', marginTop:3, fontWeight:500}}>
              {s.label}
            </div>
          </div>
        ))}
      </div>

      {/* ── Headline + Quality score ── */}
      <div style={{display:'grid', gridTemplateColumns:'1fr auto', gap:12}}>
        {eda.headline && (
          <div style={{
            background:'linear-gradient(135deg,#eef2ff,#f5f3ff)',
            border:'1.5px solid #e0e7ff', borderRadius:10,
            padding:'14px 18px', display:'flex',
            alignItems:'flex-start', gap:10
          }}>
            <span style={{fontSize:20}}>💡</span>
            <div>
              <div style={{fontSize:10, fontWeight:700, color:'#6366f1',
                textTransform:'uppercase', letterSpacing:'0.08em', marginBottom:4}}>
                Key Insight
              </div>
              <div style={{fontSize:13, color:'#374151', lineHeight:1.6}}>
                {safeStr(eda.headline)}
              </div>
            </div>
          </div>
        )}
        {qScore !== null && qColors && (
          <div style={{
            background:qColors.bg,
            border:`1.5px solid ${qColors.border}`,
            borderRadius:10, padding:'14px 20px',
            textAlign:'center', minWidth:110
          }}>
            <div style={{fontSize:10, fontWeight:700, color:qColors.color,
              textTransform:'uppercase', letterSpacing:'0.08em', marginBottom:6}}>
              Data Quality
            </div>
            <div style={{fontSize:36, fontWeight:800, color:qColors.color, lineHeight:1}}>
              {qScore}
            </div>
            <div style={{fontSize:10, color:qColors.color, marginTop:4}}>/100</div>
            <div style={{
              marginTop:8, fontSize:11, fontWeight:600,
              color:qColors.color, background:`${qColors.border}50`,
              borderRadius:6, padding:'3px 8px'
            }}>
              {eda.data_quality?.verdict || ''}
            </div>
            {Array.isArray(eda.data_quality?.issues) && eda.data_quality.issues.length > 0 && (
              <div style={{marginTop:6}}>
                {eda.data_quality.issues.map((iss,i) => (
                  <div key={i} style={{
                    fontSize:10, color:'#d97706',
